import React, { useEffect, useRef, useState } from "react";
import "../styles/GeneralChat.css";
import therapistResponses from "../data/therapistResponses";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      emotion: "🧠 Welcome",
      text: "Hi 👋 I’m your AI mental health assistant. I’m here to listen. How are you feeling today?",
    },
  ]);
  const [input, setInput] = useState("");
  const [typing, setTyping] = useState(false);
  const chatEndRef = useRef(null);

  // Auto scroll to bottom (IMPORTANT FIX)
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, typing]);

  const getBotReply = (message) => {
    const msg = message.toLowerCase();

    for (let item of therapistResponses) {
      if (item.keywords.some((word) => msg.includes(word))) {
        return {
          emotion: item.emotion,
          text: `${item.reply}\n\n🎵 Songs that may help:\n• ${item.songs.join(
            "\n• "
          )}`,
        };
      }
    }

    return {
      emotion: "🧠 Listening",
      text:
        "I’m here with you 🤍 Take your time. Would you like to tell me a bit more about what’s been on your mind?",
    };
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = {
      sender: "user",
      text: input,
    };

    setMessages((prev) => [...prev, userMessage]);
    setInput("");
    setTyping(true);

    setTimeout(() => {
      const botReply = getBotReply(input);
      setMessages((prev) => [
        ...prev,
        {
          sender: "bot",
          emotion: botReply.emotion,
          text: botReply.text,
        },
      ]);
      setTyping(false);
    }, 1200);
  };

  return (
    <div className="chat-wrapper">
      <h2 className="chat-title">🧠 General Chat</h2>

      <div className="chat-container">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`chat-bubble ${
              msg.sender === "user" ? "user" : "bot"
            }`}
          >
            {msg.sender === "bot" && (
              <div className="emotion-tag">{msg.emotion}</div>
            )}
            <p style={{ whiteSpace: "pre-line" }}>{msg.text}</p>
          </div>
        ))}

        {typing && (
          <div className="chat-bubble bot typing">
            <span></span>
            <span></span>
            <span></span>
          </div>
        )}

        <div ref={chatEndRef} />
      </div>

      <div className="input-area">
        <input
          type="text"
          placeholder="Type how you feel..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && handleSend()}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
